.darma-loader-loading-io-05 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      height: 32px;
    }
    .darma-loader-loading-io-05 i {
      display: block;
      width: 6px;
      height: 32px;
      border-radius: 999px;
      background: linear-gradient(180deg, var(--loader-color, #8b5cf6), var(--loader-secondary-color, #ddd6fe));
      transform-origin: center bottom;
      animation: darma-loader-loading-io-05-barPulse 0.75s ease-in-out infinite;
    }
    .darma-loader-loading-io-05 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loading-io-05 i:nth-child(2) { animation-delay: 0.09s; }
.darma-loader-loading-io-05 i:nth-child(3) { animation-delay: 0.18s; }
.darma-loader-loading-io-05 i:nth-child(4) { animation-delay: 0.27s; }
    @keyframes darma-loader-loading-io-05-barPulse { 0%, 100% { opacity: .25; transform: scaleY(.5); } 45% { opacity: 1; transform: scaleY(1); } }

